import java.security.SecureRandom
import java.util.concurrent.ConcurrentHashMap

class SessionTokenGenerator {
    private val secureRandom = SecureRandom()
    private val sessionTokens = ConcurrentHashMap<String, Long>()
    
    companion object {
        private const val TOKEN_LENGTH = 32
        private val CHARACTERS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    }
    
    fun generateSessionId(): String {
        return generateRandomString(32)
    }
    
    fun generateApiToken(): String {
        return generateRandomString(TOKEN_LENGTH)
    }
    
    fun isValidSession(sessionId: String): Boolean {
        return sessionTokens.containsKey(sessionId)
    }
    
    fun createSession(sessionId: String) {
        sessionTokens[sessionId] = System.currentTimeMillis()
    }
    
    fun destroySession(sessionId: String) {
        sessionTokens.remove(sessionId)
    }
    
    fun cleanupExpiredSessions(expirationMillis: Long) {
        val currentTime = System.currentTimeMillis()
        sessionTokens.keys.removeIf { sessionId ->
            val sessionTime = sessionTokens[sessionId] ?: 0L
            currentTime - sessionTime > expirationMillis
        }
    }
    
    private fun generateRandomString(length: Int): String {
        val stringBuilder = StringBuilder()
        for (i in 0 until length) {
            val randomIndex = secureRandom.nextInt(CHARACTERS.length)
            stringBuilder.append(CHARACTERS[randomIndex])
